mapper.select:
SELECT s.id, s.title, s.description, s.start_time, s.end_time, s.priority, s.status, s.category_id, c.name AS categoryName, c.color AS categoryColor FROM t_schedule s LEFT JOIN t_category c ON s.category_id = c.id
s.is_deleted = 0 AND s.user_id = #{query.userId}
AND s.title LIKE CONCAT('%', #{query.title}, '%')
AND s.category_id = #{query.categoryId}
ORDER BY s.start_time DESC
